module dijkstra_min_distance(  
    input [7:0] max_dist,  
    input [7:0] dist2,  
    input [7:0] dist3,  
    output reg [7:0] min_dist  
);  
    always @(*) begin  
        if (max_dist <= dist2 && max_dist <= dist3)  
            min_dist = max_dist;  
        else if (dist2 <= max_dist && dist2 <= dist3)  
            min_dist = dist2;  
        else  
            min_dist = dist3;  
    end  
endmodule
